import pandas as pd


class Joiner:
    def __init__(self, left_key='id', right_key='id'):
        self.left_key = left_key
        self.right_key = right_key

    def join(self, left, right):
        merged = pd.merge(left, right, left_on=self.left_key, right_on=self.right_key)
        # BUG: 'cost' column is actually named 'costs' in right df
        merged['profit'] = merged['revenue'] - merged['cost']
        return merged


def join_data(left, right):
    return Joiner().join(left, right)


def main():
    left = pd.DataFrame({'id': [1, 2], 'revenue': [100, 200]})
    right = pd.DataFrame({'id': [1, 2], 'costs': [50, 80]})
    out = join_data(left, right)
    print(out)


if __name__ == '__main__':
    main()
